sql:
SELECT county, SUM(complete) AS total_completed
FROM vaccination_data
GROUP BY county;

SELECT COUNT(DISTINCT geoid)
FROM vaccination_data
WHERE complete_rate > 0.50;

SELECT county
FROM vaccination_data
WHERE geoid = 0 AND report_date = '0' AND vaccination_type = 'Pfizer';

external_knowledge:
- "Sown the seeds" refers to initiating vaccinations;
- "Blossoming years" metaphorically refers to the age group of 18 to 24;
- "Fairer sex" is a metaphorical term referring to the female gender;
- "Garden of 2021" metaphorically represents the year 2021.

sql:
SELECT county
FROM vaccination_data
WHERE complete_rate = (
    SELECT MAX(complete_rate)
    FROM vaccination_data
);

SELECT county, complete_rate
FROM vaccination_data
WHERE complete_rate = (
  SELECT MAX(complete_rate) 
  FROM vaccination_data
);

SELECT county, initiated_rate, report_date
FROM vaccination_data
ORDER BY initiated_rate DESC;

external_knowledge:
- 'initiated_rate >= 50' means the county has a vaccination initiation rate of at least 50%;
- 'Missouri armada' refers to the total initiated vaccinations in all counties within the state of Missouri;
- 'ships sailing with the most recruits' refers to counties with high numbers of people who have initiated vaccinations;
- 'grand fleet' refers to the total number of people who have initiated vaccinations across all counties;
- 'largest ship' refers to the county with the highest number of initiated vaccinations.

sql:
SELECT COUNT(*)
FROM vaccine_supply
WHERE supply_id = 1 AND supplier_id = 1 AND vaccine_type = 'Moderna' AND quantity > 2000;

SELECT COUNT(DISTINCT vaccination_type)
FROM vaccination_data
WHERE age_group = '65+' AND gender = 'Female';

SELECT c.county_name, vd.vaccination_type
FROM counties c
INNER JOIN vaccination_data vd ON c.geoid = vd.geoid;

SELECT COUNT(*) 
FROM vaccination_data 
WHERE geoid = 100;

SELECT vaccine_type, SUM(quantity) AS total_quantity
FROM vaccine_distribution
GROUP BY vaccine_type;

SELECT vaccine_type, quantity
FROM vaccine_distribution
WHERE vaccine_type = 'Pfizer-BioNTech' AND quantity > 500;

SELECT supplier_name, contact_person
FROM vaccine_suppliers
WHERE supplier_id = 1;

SELECT county_name, population
FROM counties
WHERE population > (
    SELECT AVG(population)
    FROM counties
);

SELECT permission_name
FROM permissions
WHERE permission_id = 0;
